const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    business_name: r.fields.business_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    phone: r.fields.phone || '',
    category: r.fields.category || '',
    google_rating: r.fields.google_rating || null,
    review_count: r.fields.review_count || 0
  }
}));

const html = $input.item.json.data || $input.item.json || '';
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

let text = htmlStr
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ').trim().substring(0, 3000);

// Carry original record data forward — reach back to Split Into Items (1:1 item pairing)
const record = $('Split Into Items').item.json;
return [{ json: { ...record, website_text: text, website_fetch_status: 'Success' } }];

const response = $input.item.json;
const content = response.content?.[0]?.text || '';
const prevRecord = $('Build Claude Prompt').item.json;

let parsed;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { score: 0, signals: ['Parse error — Claude returned invalid JSON'], summary: 'Failed to parse Claude response', has_booking_system: null, mentions_software: null, software_mentioned: null };
}

return [{ json: { ...prevRecord, ai_score: parsed.score || 0, ai_signals: Array.isArray(parsed.signals) ? parsed.signals.join(', ') : '', ai_summary: parsed.summary || '', has_booking_system: parsed.has_booking_system, mentions_software: parsed.mentions_software, software_mentioned: parsed.software_mentioned, website_fetch_status: prevRecord.website_fetch_status || 'Success' } }];

// This node runs once per item — aggregate node would be needed for a true
// per-batch Slack message. For now we suppress all but the last item using
// n8n's item index to avoid 25 pings for 25 records.
// A cleaner solution is to add a Summarize node before this.
const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
return [{ json: { slackUrl, slackBody: { text: '📊 *Workflow B — Record Scored*\nAI scoring run in progress. Check Airtable Scored records for updated ai_score values.' } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: { slackUrl, slackBody: { text: `🚨 *Workflow B Error*\n${err.execution?.error?.message || 'Unknown error'}` } } }];
